class Solution {
public:
    bool canIWin(int maxChoosableInteger, int desiredTotal) {
        if (desiredTotal <= 0) return true;
        vector<bool> used(maxChoosableInteger + 1, false);
        return dfs(used, 0, desiredTotal);
    }
    bool dfs(vector<bool>& used, int total, int desiredTotal) {
        if (total >= desiredTotal) return true;
        for (int i = 1; i <= maxChoosableInteger; i++) {
            if (!used[i]) {
                used[i] = true;
                if (!dfs(used, total + i, desiredTotal)) {
                    used[i] = false;
                    return true;
                }
                used[i] = false;
            }
        }
        return false;
    }
};
